#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PrimitiveTypeEnum {
    U8,
    I8,
    U16,
    I16,
    U32,
    I32,
    U64,
    I64,
    U128,
    I128,
    Isize,
    Usize,
    F32,
    F64,
    Bool,
    Str,
    Char,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for PrimitiveTypeEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            28 => Ok(Self::U8), // "u8"
            29 => Ok(Self::I8), // "i8"
            30 => Ok(Self::U16), // "u16"
            31 => Ok(Self::I16), // "i16"
            32 => Ok(Self::U32), // "u32"
            33 => Ok(Self::I32), // "i32"
            34 => Ok(Self::U64), // "u64"
            35 => Ok(Self::I64), // "i64"
            36 => Ok(Self::U128), // "u128"
            37 => Ok(Self::I128), // "i128"
            38 => Ok(Self::Isize), // "isize"
            39 => Ok(Self::Usize), // "usize"
            40 => Ok(Self::F32), // "f32"
            41 => Ok(Self::F64), // "f64"
            42 => Ok(Self::Bool), // "bool"
            43 => Ok(Self::Str), // "str"
            44 => Ok(Self::Char), // "char"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for PrimitiveTypeEnum",
            ))),
        }
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for PrimitiveTypeEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("PrimitiveTypeEnum is receive-only"))
    }
}

