#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FragmentSpecifierEnum {
    Block,
    Expr,
    Expr2021,
    Ident,
    Item,
    Lifetime,
    Literal,
    Meta,
    Pat,
    PatParam,
    Path,
    Stmt,
    Tt,
    Ty,
    Vis,
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::FromNapiValue for FragmentSpecifierEnum {
    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        let kind_id: u16 = u16::from_napi_value(env, napi_val)?;
        match kind_id {
            293 => Ok(Self::Block), // "block"
            14 => Ok(Self::Expr), // "expr"
            15 => Ok(Self::Expr2021), // "expr_2021"
            16 => Ok(Self::Ident), // "ident"
            17 => Ok(Self::Item), // "item"
            219 => Ok(Self::Lifetime), // "lifetime"
            19 => Ok(Self::Literal), // "literal"
            20 => Ok(Self::Meta), // "meta"
            21 => Ok(Self::Pat), // "pat"
            22 => Ok(Self::PatParam), // "pat_param"
            23 => Ok(Self::Path), // "path"
            24 => Ok(Self::Stmt), // "stmt"
            25 => Ok(Self::Tt), // "tt"
            26 => Ok(Self::Ty), // "ty"
            27 => Ok(Self::Vis), // "vis"
            other => Err(::napi::Error::from_reason(format!(
                "unknown kind id {{other}} for FragmentSpecifierEnum",
            ))),
        }
    }
}

#[cfg(feature = "napi-bindings")]
impl ::napi::bindgen_prelude::ToNapiValue for FragmentSpecifierEnum {
    unsafe fn to_napi_value(
        _env: ::napi::sys::napi_env,
        _val: Self,
    ) -> ::napi::Result<::napi::sys::napi_value> {
        Err(::napi::Error::from_reason("FragmentSpecifierEnum is receive-only"))
    }
}

impl ::std::fmt::Display for FragmentSpecifierEnum {
    fn fmt(&self, f: &mut ::std::fmt::Formatter<'_>) -> ::std::fmt::Result {
        f.write_str(match self {
            Self::Block => "block",
            Self::Expr => "expr",
            Self::Expr2021 => "expr_2021",
            Self::Ident => "ident",
            Self::Item => "item",
            Self::Lifetime => "lifetime",
            Self::Literal => "literal",
            Self::Meta => "meta",
            Self::Pat => "pat",
            Self::PatParam => "pat_param",
            Self::Path => "path",
            Self::Stmt => "stmt",
            Self::Tt => "tt",
            Self::Ty => "ty",
            Self::Vis => "vis",
        })
    }
}

impl RenderableTransport for FragmentSpecifierEnum {
    fn render_into(
        &self,
        dest: &mut dyn ::std::fmt::Write,
    ) -> Result<(), ::askama::Error> {
        dest.write_str(match self {
            Self::Block => "block",
            Self::Expr => "expr",
            Self::Expr2021 => "expr_2021",
            Self::Ident => "ident",
            Self::Item => "item",
            Self::Lifetime => "lifetime",
            Self::Literal => "literal",
            Self::Meta => "meta",
            Self::Pat => "pat",
            Self::PatParam => "pat_param",
            Self::Path => "path",
            Self::Stmt => "stmt",
            Self::Tt => "tt",
            Self::Ty => "ty",
            Self::Vis => "vis",
        }).map_err(::askama::Error::from)
    }
}

